const ARTISTS = {"Leonardo da Vinci": {"life": "1452–1519", "why": "The Renaissance model of artist as scientist, observer and inventor.", "timeline": ["1452 born near Vinci", "1480s works in Milan", "1495–1498 paints The Last Supper", "c. 1503 begins Mona Lisa", "1519 dies in France"]}, "Sandro Botticelli": {"life": "c. 1445–1510", "why": "Made myth, line and ideal beauty central to Florentine Renaissance art.", "timeline": ["c. 1445 born in Florence", "1480s paints Primavera and Birth of Venus", "1490s affected by Savonarola’s Florence", "1510 dies in Florence"]}, "Johannes Vermeer": {"life": "1632–1675", "why": "Master of quiet light, domestic stillness and psychological suspension.", "timeline": ["1632 born in Delft", "1650s begins mature interiors", "c. 1658 paints The Milkmaid", "c. 1665 paints Girl with a Pearl Earring", "1675 dies in debt"]}, "Rembrandt van Rijn": {"life": "1606–1669", "why": "One of art’s greatest painters of light, age, empathy and human presence.", "timeline": ["1606 born in Leiden", "1632 paints Anatomy Lesson", "1642 paints The Night Watch", "1650s–1660s late self-portraits", "1669 dies in Amsterdam"]}, "Vincent van Gogh": {"life": "1853–1890", "why": "Turned colour and brushwork into emotional intensity.", "timeline": ["1853 born in the Netherlands", "1886 moves to Paris", "1888 works in Arles", "1889 paints The Starry Night", "1890 dies in Auvers-sur-Oise"]}, "Diego Velázquez": {"life": "1599–1660", "why": "Spanish master of realism, court portraiture and the mystery of looking.", "timeline": ["1599 born in Seville", "1623 becomes court painter", "1630s paints royal and historical works", "1656 paints Las Meninas", "1660 dies in Madrid"]}, "Francisco Goya": {"life": "1746–1828", "why": "Bridged court painting, modern darkness, political violence and psychological horror.", "timeline": ["1746 born in Fuendetodos", "1780s becomes court painter", "1814 paints The Third of May", "1819–1823 creates Black Paintings", "1828 dies in Bordeaux"]}, "Pablo Picasso": {"life": "1881–1973", "why": "Changed the rules of modern art through Cubism, reinvention and restless experimentation.", "timeline": ["1881 born in Málaga", "1907 paints Les Demoiselles d’Avignon", "1910s develops Cubism", "1937 paints Guernica", "1973 dies in Mougins"]}, "Claude Monet": {"life": "1840–1926", "why": "Made light, atmosphere and repeated perception central to modern painting.", "timeline": ["1840 born in Paris", "1872 paints Impression, Sunrise", "1874 first Impressionist exhibition", "1890s serial works", "1926 dies at Giverny"]}, "Édouard Manet": {"life": "1832–1883", "why": "Forced modern life into old painting formats and helped trigger modernism.", "timeline": ["1832 born in Paris", "1863 shows Olympia and Luncheon on the Grass", "1870s engages with Impressionists", "1883 dies in Paris"]}, "J. M. W. Turner": {"life": "1775–1851", "why": "Turned landscape into light, weather, history and modern sensation.", "timeline": ["1775 born in London", "1802 becomes Royal Academician", "1839 paints The Fighting Temeraire", "1844 paints Rain, Steam and Speed", "1851 dies in London"]}, "Frida Kahlo": {"life": "1907–1954", "why": "Made self-portraiture into symbolic autobiography and cultural identity.", "timeline": ["1907 born in Coyoacán", "1925 severe bus accident", "1939 paints The Two Fridas", "1940 paints Self-Portrait with Thorn Necklace", "1954 dies in Mexico City"]}, "Caravaggio": {"life": "1571–1610", "why": "Made religious painting immediate, physical and dramatically lit.", "timeline": ["1571 born in Milan", "1590s works in Rome", "1599–1600 paints Calling of Saint Matthew", "1606 flees Rome", "1610 dies near Porto Ercole"]}, "Jacques-Louis David": {"life": "1748–1825", "why": "Turned classical style into moral, revolutionary and imperial image-making.", "timeline": ["1748 born in Paris", "1784 paints Oath of the Horatii", "1793 paints Death of Marat", "1801 paints Napoleon Crossing the Alps", "1825 dies in Brussels"]}, "Pieter Bruegel the Elder": {"life": "c. 1525–1569", "why": "Made peasant life, landscape, moral comedy and social observation monumental.", "timeline": ["c. 1525 born probably in Breda region", "1559 paints Netherlandish Proverbs", "1563 paints Tower of Babel", "1565 paints seasonal landscapes", "1569 dies in Brussels"]}, "Albrecht Dürer": {"life": "1471–1528", "why": "Elevated printmaking, self-portraiture and observation in Northern Renaissance art.", "timeline": ["1471 born in Nuremberg", "1490s travels and studies Italian art", "1500 paints famous self-portrait", "1515 creates Rhinoceros woodcut", "1528 dies in Nuremberg"]}, "Titian": {"life": "c. 1488–1576", "why": "The great Venetian master of colour, myth, portraiture and painterly surface.", "timeline": ["c. 1488 born in Pieve di Cadore", "1516–1518 paints Assumption", "1538 paints Venus of Urbino", "1550s late mythologies", "1576 dies in Venice"]}, "Peter Paul Rubens": {"life": "1577–1640", "why": "Baroque master of movement, flesh, colour and diplomatic spectacle.", "timeline": ["1577 born in Siegen", "1600 travels to Italy", "1609 returns to Antwerp", "1610s paints major altarpieces", "1640 dies in Antwerp"]}, "Gustave Courbet": {"life": "1819–1877", "why": "Made Realism confront ordinary life, labour and social reality at grand scale.", "timeline": ["1819 born in Ornans", "1849 paints Stone Breakers", "1850 exhibits Burial at Ornans", "1855 sets up Pavilion of Realism", "1877 dies in Switzerland"]}, "Mary Cassatt": {"life": "1844–1926", "why": "Central Impressionist painter of modern women, children, care and spectatorship.", "timeline": ["1844 born in Pennsylvania", "1870s settles in Paris", "1878 paints Little Girl in a Blue Armchair", "1890s influenced by Japanese prints", "1926 dies in France"]}, "Paul Cézanne": {"life": "1839–1906", "why": "Rebuilt painting through structure, colour and form, becoming a bridge to Cubism.", "timeline": ["1839 born in Aix-en-Provence", "1870s exhibits with Impressionists", "1890s paints Card Players and still lifes", "1900s paints Mont Sainte-Victoire repeatedly", "1906 dies in Aix"]}, "Henri Matisse": {"life": "1869–1954", "why": "Liberated colour and made modern art joyous, decorative and structurally bold.", "timeline": ["1869 born in Le Cateau-Cambrésis", "1905 leads Fauvist shock", "1908 paints Red Room", "1910 paints The Dance", "1954 dies in Nice"]}, "Marcel Duchamp": {"life": "1887–1968", "why": "Changed art by making selection, context and idea as important as craft.", "timeline": ["1887 born in Blainville-Crevon", "1912 paints Nude Descending a Staircase", "1917 submits Fountain", "1919 creates L.H.O.O.Q.", "1968 dies in France"]}, "René Magritte": {"life": "1898–1967", "why": "Made ordinary images philosophically strange with clarity and wit.", "timeline": ["1898 born in Belgium", "1920s joins Surrealist circles", "1929 paints Treachery of Images", "1950s develops iconic bowler-hat imagery", "1967 dies in Brussels"]}, "Auguste Rodin": {"life": "1840–1917", "why": "Reinvented sculpture through expressive surfaces, fragments and psychological force.", "timeline": ["1840 born in Paris", "1880 begins Gates of Hell", "1880s creates The Kiss and Burghers of Calais", "1904 casts The Thinker", "1917 dies near Paris"]}};
const APP_VERSION = "1.2.1";
const STORAGE = { saved: "artwise_saved_v1", seen: "artwise_seen_v1" };
const state = { section: "today", query: "", movement: "All", wallpaper: null };
const $ = s => document.querySelector(s);
const $$ = s => Array.from(document.querySelectorAll(s));
let imageObserver = null;

function safeParse(k,f){try{const r=localStorage.getItem(k);return r?JSON.parse(r):f}catch{return f}}
function saveJSON(k,v){localStorage.setItem(k,JSON.stringify(v))}
function getSaved(){return new Set(safeParse(STORAGE.saved,[]))}
function setSaved(s){saveJSON(STORAGE.saved,[...s])}
function getSeen(){return safeParse(STORAGE.seen,{})}
function setSeen(o){saveJSON(STORAGE.seen,o)}
function esc(s){return String(s??"").replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c]))}
function norm(s){return String(s||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"")}
function todayKey(){const d=new Date();return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`}
function displayDate(){return new Date().toLocaleDateString(undefined,{weekday:"long",year:"numeric",month:"long",day:"numeric"})}
function dailyArtworkIndex(){const key=todayKey();let h=0;for(let i=0;i<key.length;i++)h=((h<<5)-h+key.charCodeAt(i))|0;return Math.abs(h)%ARTWORKS.length}
function getTodayArtwork(){return ARTWORKS[dailyArtworkIndex()]}
function id(a){return `${a.artist}::${a.title}`}
function movementsList(){return [...new Set(ARTWORKS.map(a=>a.movement).filter(Boolean))].sort()}
function thumbUrl(url, width=520){if(!url)return ""; const sep=url.includes("?")?"&":"?"; return `${url}${sep}width=${width}`;}
function displayUrl(a, mode){return mode==="compact" ? thumbUrl(a.image, 520) : a.image;}
function filtered(){const q=norm(state.query);return ARTWORKS.filter(a=>{const m=state.movement==="All"||a.movement===state.movement;const t=norm([a.title,a.artist,a.year,a.movement,a.location,a.whySpecial,a.whyKnow,a.lesson,...(a.notice||[])].join(" "));return m&&(!q||t.includes(q))})}
function markSeen(a){const seen=getSeen();seen[id(a)]=new Date().toISOString();setSeen(seen)}
function findArt(x){return ARTWORKS.find(a=>id(a)===x)}
function toggleSaved(a){const s=getSaved();s.has(id(a))?s.delete(id(a)):s.add(id(a));setSaved(s);render()}
async function downloadArtwork(a){const fn=`${a.artist}-${a.title}`.replace(/[^a-z0-9\- ]/gi,"").replace(/\s+/g,"-").toLowerCase()+".jpg";try{const r=await fetch(a.image,{mode:"cors"});const b=await r.blob();const u=URL.createObjectURL(b);const link=document.createElement("a");link.href=u;link.download=fn;document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(u),1500)}catch{window.open(a.image,"_blank","noopener,noreferrer")}}
function lazyImg(src, alt, mode){
  const safeSrc = esc(src);
  const safeAlt = esc(alt);
  if(mode==="compact") {
    return `<img class="lazy-img" data-src="${safeSrc}" alt="${safeAlt}" loading="lazy" decoding="async" fetchpriority="low" onerror="this.closest('.image-wrap')?.classList.add('image-failed');this.remove();">`;
  }
  return `<img src="${safeSrc}" alt="${safeAlt}" loading="eager" decoding="async" fetchpriority="high" onerror="this.closest('.image-wrap')?.classList.add('image-failed');this.remove();">`;
}
function setupLazyImages(){const imgs=$$(".lazy-img[data-src]"); if(!imgs.length)return; if(!("IntersectionObserver" in window)){imgs.forEach(img=>{img.src=img.dataset.src; img.removeAttribute("data-src");});return;} if(imageObserver)imageObserver.disconnect(); imageObserver=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target; img.src=img.dataset.src; img.removeAttribute("data-src"); img.addEventListener("load",()=>{img.classList.add("loaded");img.closest('.image-wrap')?.classList.remove('skeleton');},{once:true}); imageObserver.unobserve(img);}})},{rootMargin:"500px 0px",threshold:0.01}); imgs.forEach(img=>imageObserver.observe(img));}
function card(a,mode="full"){const saved=getSaved().has(id(a));const imgSrc=displayUrl(a,mode);return `<article class="art-card"><div class="image-wrap skeleton">${lazyImg(imgSrc,`${a.title} by ${a.artist}`,mode)}<div class="image-gradient"></div><div class="image-label">${esc(a.movement)}</div></div><div class="art-content"><div class="meta-row"><span>${esc(a.year)}</span><span>${esc(a.location)}</span></div><h2>${esc(a.title)}</h2><p class="artist">by ${esc(a.artist)}</p><div class="action-row"><button class="primary-btn" data-action="download" data-art="${esc(id(a))}">Save image</button><button class="secondary-btn" data-action="wallpaper" data-art="${esc(id(a))}">Wallpaper view</button><button class="secondary-btn ${saved?"active":""}" data-action="save" data-art="${esc(id(a))}">${saved?"Saved ★":"Save ★"}</button></div>${mode==="compact"?`<p class="why-mini">${esc(a.whySpecial)}</p>`:`<section class="lesson-block"><div class="eyebrow">Why it is special</div><p>${esc(a.whySpecial)}</p></section><section class="lesson-block"><div class="eyebrow">What to notice</div><ul>${(a.notice||[]).map(n=>`<li>${esc(n)}</li>`).join("")}</ul></section><section class="lesson-block"><div class="eyebrow">Why you should know this</div><p>${esc(a.whyKnow)}</p></section><section class="takeaway"><div class="eyebrow">The art teacher takeaway</div><p>${esc(a.lesson)}</p></section><p class="small-note">Wallpaper tip: use Wallpaper view for a cleaner full-screen image, then long-press/save on mobile if direct download is blocked.</p>`}</div></article>`}
function controls(){return `<section class="controls"><input id="searchBox" class="search-input" type="search" placeholder="Search artwork, artist, movement, idea..." value="${esc(state.query)}"><select id="movementFilter" class="select-control"><option value="All">All movements</option>${movementsList().map(m=>`<option value="${esc(m)}" ${state.movement===m?"selected":""}>${esc(m)}</option>`).join("")}</select><button id="clearFilters" class="secondary-btn">Clear</button></section>`}
function renderToday(){const a=getTodayArtwork();markSeen(a);$("#app").innerHTML=`<section class="hero"><div><div class="eyebrow">ArtWise v${APP_VERSION} · ${displayDate()}</div><h1>Today’s artwork</h1><p>One famous work a day, explained without museum fog. Look for two minutes. Understand why it matters.</p></div><button class="secondary-btn" data-nav="gallery">Explore archive</button></section>${card(a,"today")}`;setupLazyImages()}
function renderGallery(savedOnly=false){const saved=getSaved();const arr=filtered().filter(a=>!savedOnly||saved.has(id(a)));$("#app").innerHTML=`<section class="page-head"><div><h1>${savedOnly?"Saved artworks":"Gallery archive"}</h1><p>${arr.length} artwork${arr.length===1?"":"s"}. Gallery images use lighter thumbnails for faster loading.</p></div></section>${controls()}<section class="grid">${arr.map(a=>card(a,"compact")).join("")||`<div class="empty-state">${savedOnly?"No saved artworks yet.":"No artworks found."}</div>`}</section>`;setupLazyImages()}
function renderMovements(){const keys=Object.keys(MOVEMENTS).sort();$("#app").innerHTML=`<section class="page-head"><div><h1>Movements explained</h1><p>Short, non-pretentious explanations of the art movements inside the app.</p></div></section><section class="learn-grid">${keys.map(k=>{const m=MOVEMENTS[k];return `<article class="learn-card movement-card"><div class="eyebrow">${esc(m.period||"")}</div><h2>${esc(k)}</h2><p>${esc(m.simple)}</p><div class="mini-list">${(m.lookFor||[]).map(x=>`<span>${esc(x)}</span>`).join("")}</div><button class="secondary-btn" data-movement="${esc(k)}">See artworks</button></article>`}).join("")}</section>`}
function renderArtists(){const keys=Object.keys(ARTISTS).sort();$("#app").innerHTML=`<section class="page-head"><div><h1>Artist timelines</h1><p>Quick context for the artists you keep seeing in the daily artworks.</p></div></section><section class="timeline-grid">${keys.map(k=>{const a=ARTISTS[k];return `<article class="timeline-card"><div class="eyebrow">${esc(a.life)}</div><h2>${esc(k)}</h2><p>${esc(a.why)}</p><ol>${(a.timeline||[]).map(x=>`<li>${esc(x)}</li>`).join("")}</ol></article>`}).join("")}</section>`}
function renderLearn(){$("#app").innerHTML=`<section class="page-head"><div><h1>How to look at art</h1><p>A tiny framework for not feeling awkward in front of famous paintings.</p></div></section><section class="learn-grid">${[["Start with what your eye does","Before reading the label, notice where your eye goes first. Artists control attention with light, contrast, faces, hands and movement."],["Ask what changed","Why did this artwork matter in its own time? Did it change realism, emotion, politics, technique, scale or the role of the viewer?"],["Look for tension","Great art usually contains a tension: calm vs drama, beauty vs violence, realism vs symbol, private emotion vs public meaning."],["Separate subject from method","A painting of a person is not only about that person. It may be about light, power, psychology, status, myth, or the act of looking."],["Do not worship fame blindly","Famous does not always mean emotionally better. But fame usually means the work shaped a visual language that came after it."],["One strong observation is enough","You do not need to decode everything. One real observation beats ten memorised museum sentences."]].map(x=>`<article class="learn-card"><h2>${esc(x[0])}</h2><p>${esc(x[1])}</p></article>`).join("")}</section>`}
function renderWallpaper(){const a=state.wallpaper||getTodayArtwork();$("#app").innerHTML=`<section class="wallpaper-page"><div class="wallpaper-frame"><img src="${esc(a.image)}" alt="${esc(a.title)}" decoding="async"></div><div class="wallpaper-panel"><div class="eyebrow">Wallpaper view</div><h1>${esc(a.title)}</h1><p>by ${esc(a.artist)} · ${esc(a.year)}</p><div class="action-row"><button class="primary-btn" data-action="download" data-art="${esc(id(a))}">Download image</button><button class="secondary-btn" data-nav="today">Back</button></div><p class="small-note">On iPhone/Android, if download opens the image in a new tab, long-press the image and choose Save to Photos/Gallery. Then set it as wallpaper from your device settings.</p></div></section>`}
function renderAbout(){const saved=getSaved().size, seen=Object.keys(getSeen()).length;$("#app").innerHTML=`<section class="about-card"><h1>About ArtWise</h1><p>ArtWise is a daily art teacher: one famous artwork per day, explained through practical looking rather than academic fog.</p><div class="stat-grid"><div><strong>${ARTWORKS.length}</strong><span>artworks in v1.2</span></div><div><strong>${seen}</strong><span>viewed</span></div><div><strong>${saved}</strong><span>saved</span></div></div><p class="small-note">v1.2 uses lighter gallery thumbnails and lazy loading. Today and Wallpaper views still use larger images where possible.</p></section>`}
function render(){$$(".nav-btn").forEach(b=>b.classList.toggle("active",b.dataset.nav===state.section));if(state.section==="today")renderToday();if(state.section==="gallery")renderGallery(false);if(state.section==="saved")renderGallery(true);if(state.section==="movements")renderMovements();if(state.section==="artists")renderArtists();if(state.section==="learn")renderLearn();if(state.section==="wallpaper")renderWallpaper();if(state.section==="about")renderAbout()}
function setSection(s){state.section=s;state.query="";state.movement="All";render()}
function handleClick(e){const t=e.target.closest("button,[data-nav],[data-action],[data-movement]");if(!t)return;if(t.dataset.movement){state.section="gallery";state.movement=t.dataset.movement;state.query="";render();return}if(t.dataset.nav){setSection(t.dataset.nav);return}if(t.id==="clearFilters"){state.query="";state.movement="All";render();return}const a=findArt(t.dataset.art);if(t.dataset.action==="save"&&a)toggleSaved(a);if(t.dataset.action==="download"&&a)downloadArtwork(a);if(t.dataset.action==="wallpaper"&&a){state.wallpaper=a;state.section="wallpaper";render()}}
function handleInput(e){if(e.target?.id==="searchBox"){state.query=e.target.value||"";state.section==="saved"?renderGallery(true):renderGallery(false)}}
function handleChange(e){if(e.target?.id==="movementFilter"){state.movement=e.target.value||"All";state.section==="saved"?renderGallery(true):renderGallery(false)}}
function boot(){document.body.innerHTML=`<div class="app-shell"><header class="topbar"><div class="brand"><div class="logo-mark">A</div><div><strong>ArtWise</strong><span>Daily art teacher</span></div></div><nav class="nav"><button class="nav-btn active" data-nav="today">Today</button><button class="nav-btn" data-nav="gallery">Gallery</button><button class="nav-btn" data-nav="saved">Saved</button><button class="nav-btn" data-nav="movements">Movements</button><button class="nav-btn" data-nav="artists">Artists</button><button class="nav-btn" data-nav="learn">How to look</button><button class="nav-btn" data-nav="about">About</button></nav></header><main id="app"></main></div>`;document.addEventListener("click",handleClick);document.addEventListener("input",handleInput);document.addEventListener("change",handleChange);if("serviceWorker"in navigator)navigator.serviceWorker.register("./service-worker.js").catch(()=>{});render()}
document.addEventListener("DOMContentLoaded",boot);
